"    }\n" +
"  }\n" +
"\n" +
"  lastCols = cols;\n" +
"  lastRows = rows;\n" +
"}\n" +
"\n" +
"function countNeighbors(x, y, cols, rows) {\n" +
"  var count = 0;\n" +
"  var dx, dy, nx, ny;\n" +
"\n" +
"  for (dy = -1; dy <= 1; dy++) {\n" +
"    for (dx = -1; dx <= 1; dx++) {\n" +
"      if (dx === 0 && dy === 0) {\n" +
"        continue;\n" +
"      }\n" +
"      nx = (x + dx + cols) % cols;\n" +
"      ny = (y + dy + rows) % rows;\n" +
"      count += cells[ny][nx];\n" +
"    }\n" +
"  }\n" +
"\n" +
"  return count;\n" +
"}\n" +
"\n" +
"function step(cols, rows) {\n" +
"  var x, y, alive, neighbors, willLive, tmp;\n" +
"\n" +
"  for (y = 0; y < rows; y++) {\n" +
"    for (x = 0; x < cols; x++) {\n" +
"      alive = cells[y][x];\n" +
"      neighbors = countNeighbors(x, y, cols, rows);\n" +
"      willLive = alive ? (neighbors === 2 || neighbors === 3) : (neighbors === 3);\n" +
"      next[y][x] = willLive ? 1 : 0;\n" +
"    }\n" +
"  }\n" +
"\n" +
"  tmp = cells;\n" +
"  cells = next;\n" +
"  next = tmp;\n" +
"}\n" +
"\n" +
"exports.frame = function (grid) {\n" +
"  var x, y, cell;\n" +
"\n" +
"  if (cells === null || lastCols !== width || lastRows !== height) {\n" +
"    setup(width, height);\n" +
"  }\n" +
"\n" +
"  if (frame % STEP_EVERY_N_FRAMES === 0) {\n" +
"    step(width, height);\n" +
"  }\n" +
"\n" +
"  for (y = 0; y < height; y++) {\n" +
"    for (x = 0; x < width; x++) {\n" +
"      cell = grid[y][x];\n" +
"      if (cells[y][x]) {\n" +
"        cell.ch = '#';\n" +
"        cell.fg = 'brightwhite';\n" +
"      } else {\n" +
"        cell.ch = ' ';\n" +
"        cell.fg = 'default';\n" +
"      }\n" +
"    }\n" +
"  }\n" +
"};\n"
