"];\n" +
"\n" +
"var p = new Array(512);\n" +
"(function () {\n" +
"  var i;\n" +
"  for (i = 0; i < 256; i++) {\n" +
"    p[256 + i] = p[i] = permutation[i];\n" +
"  }\n" +
"})();\n" +
"\n" +
"function noise(x, y, z) {\n" +
"  var X = Math.floor(x) & 255;\n" +
"  var Y = Math.floor(y) & 255;\n" +
"  var Z = Math.floor(z) & 255;\n" +
"  x -= Math.floor(x);\n" +
"  y -= Math.floor(y);\n" +
"  z -= Math.floor(z);\n" +
"  var u = fade(x);\n" +
"  var v = fade(y);\n" +
"  var w = fade(z);\n" +
"  var A = p[X] + Y, AA = p[A] + Z, AB = p[A + 1] + Z;\n" +
"  var B = p[X + 1] + Y, BA = p[B] + Z, BB = p[B + 1] + Z;\n" +
"\n" +
"  return lerp(w, lerp(v, lerp(u, grad(p[AA], x, y, z),\n" +
"                                 grad(p[BA], x - 1, y, z)),\n" +
"                         lerp(u, grad(p[AB], x, y - 1, z),\n" +
"                                 grad(p[BB], x - 1, y - 1, z))),\n" +
"                 lerp(v, lerp(u, grad(p[AA + 1], x, y, z - 1),\n" +
"                                 grad(p[BA + 1], x - 1, y, z - 1)),\n" +
"                         lerp(u, grad(p[AB + 1], x, y - 1, z - 1),\n" +
"                                 grad(p[BB + 1], x - 1, y - 1, z - 1))));\n" +
"}\n"
